export default function hoverConfig(e) {

let idElement = e.target.id
let timer

if(e.type === 'mouseenter'){
        let date = new Date();
        timer = parseInt(`${date.getHours()}:${date.getMinutes()}:${date.getSeconds()}`)
        console.log(timer);      
        
    }else if(e.type === 'mouseleave'){
        
        let date = new Date();
        let finalTime = parseInt(`${date.getHours()}:${date.getMinutes()}:${date.getSeconds()}`)
        console.log(finalTime);
        console.log(finalTime - timer);

    }


}
